return [{
  json: {
    workflow_id: 'CWF-330',
    vein: 'context_engineering_vein',
    dossier_id: $json.dossier_id || ($json.platform_package_packet && $json.platform_package_packet.dossier_ref) || 'TEST-DOSSIER',
    platform_package_packet: $json.platform_package_packet || $json,
    target_platform: $json.target_platform || ($json.platform_package_packet && $json.platform_package_packet.payload && $json.platform_package_packet.payload.context && $json.platform_package_packet.payload.context.target_platform) || 'youtube',
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString()
  }
}];

const ppp = $json.platform_package_packet || {};
const pppPayload = ppp.payload || {};

const validationErrors = [];
if (!ppp.instance_id) validationErrors.push('platform_package_packet missing instance_id');
if (!pppPayload.context) validationErrors.push('platform_package_packet missing context section');
if (!pppPayload.narrative) validationErrors.push('platform_package_packet missing narrative section');

if (validationErrors.length > 0) {
  throw new Error('CWF-330 input validation failed: ' + validationErrors.join('; '));
}

return [{
  json: {
    ...$json,
    source_platform_packet_id: ppp.instance_id,
    source_context_id: pppPayload.context && pppPayload.context.sourced_from_packet_id,
    platform_metadata: pppPayload.context && pppPayload.context.platform_metadata,
    platform_structure: pppPayload.narrative && pppPayload.narrative.platform_structured_body,
    input_validation: 'PASSED'
  }
}];

const platform = $json.target_platform || 'youtube';
const metadata = $json.platform_metadata || {};
const title = metadata.title || metadata.meta_title || metadata.episode_title || metadata.subject_line || 'Content Piece';

const thumbnailBriefs = {
  youtube: {
    dimensions: '1280x720px',
    format: 'JPG or PNG',
    style: 'Bold text overlay with high-contrast background',
    primary_text: title.substring(0, 30),
    secondary_text: 'Subtitle or supporting claim (under 20 chars)',
    visual_direction: 'Close-up of subject or striking visual metaphor for main claim',
    color_palette: 'Brand primary + high contrast accent',
    text_placement: 'Left-aligned with subject on right third',
    face_presence: 'Optional â€” emotive expression preferred if used',
    do_not_use: ['stock_photo_generic', 'clickbait_false_imagery', 'misleading_text']
  },
  blog: {
    dimensions: '1200x630px',
    format: 'JPG or WebP',
    style: 'Clean editorial with minimal text overlay',
    primary_text: title.substring(0, 60),
    visual_direction: 'Conceptual illustration or relevant editorial photo',
    color_palette: 'Brand secondary with neutral background',
    do_not_use: ['stock_photo_generic', 'misleading_text']
  },
  podcast: {
    dimensions: '3000x3000px (square)',
    format: 'JPG',
    style: 'Episode art with show branding',
    primary_text: 'Episode title under 50 chars',
    visual_direction: 'Show logo prominent, episode number visible',
    color_palette: 'Consistent with show brand',
    do_not_use: ['off_brand_colors', 'illegible_small_text']
  },
  email: {
    dimensions: '600x200px header',
    format: 'JPG or PNG',
    style: 'Clean header banner with brand elements',
    primary_text: 'Brief header tagline',
    visual_direction: 'Minimal, mobile-optimized, fast-loading',
    color_palette: 'Brand primary',
    do_not_use: ['large_file_size', 'text_only_images']
  }
};

const thumbnailBrief = thumbnailBriefs[platform] || thumbnailBriefs['youtube'];

return [{
  json: {
    ...$json,
    thumbnail_brief: thumbnailBrief,
    thumbnail_brief_generated: true
  }
}];

const platform = $json.target_platform || 'youtube';
const ppp = $json.platform_package_packet || {};
const pppPayload = ppp.payload || {};
const structure = $json.platform_structure || {};

const brollCues = {
  youtube: [
    { section: 'hook_30s', cue: 'Opening visual hook â€” dynamic shot establishing the main claim', type: 'b_roll', duration: '3-5s clips' },
    { section: 'intro_60s', cue: 'Presenter on camera or voice-over with relevant context visuals', type: 'on_camera_or_b_roll', duration: '5-10s clips' },
    { section: 'body_sections', cue: 'Evidence visuals, data graphics, and supporting footage per claim', type: 'b_roll_plus_motion_graphics', duration: '3-8s per claim' },
    { section: 'cta_60s', cue: 'Subscribe animation, social proof visuals', type: 'motion_graphic', duration: '5s' },
    { section: 'outro_30s', cue: 'End screen with subscribe button and related video cards', type: 'end_screen', duration: '20s' }
  ],
  blog: [
    { section: 'featured_image', cue: 'Hero image representing main claim', type: 'static_image', dimensions: '1200x630' },
    { section: 'inline_images', cue: 'Supporting images per section heading (1 per major section)', type: 'static_image', dimensions: '800x450' },
    { section: 'infographic', cue: 'Data visualization for key statistics if present', type: 'infographic', dimensions: '600x900' }
  ],
  podcast: [
    { section: 'audiogram', cue: 'Key quote audiogram for social promotion (15-30s clip)', type: 'audiogram', dimensions: '1080x1080' },
    { section: 'episode_art', cue: 'Episode-specific cover art', type: 'static_image', dimensions: '3000x3000' }
  ],
  email: [
    { section: 'header_banner', cue: 'Branded header image', type: 'static_image', dimensions: '600x200' },
    { section: 'cta_button', cue: 'Styled CTA button graphic', type: 'button_graphic', dimensions: '300x60' }
  ]
};

const broll = brollCues[platform] || brollCues['youtube'];

return [{
  json: {
    ...$json,
    broll_cue_list: broll,
    broll_brief_generated: true
  }
}];

const platform = $json.target_platform || 'youtube';

const captionBriefs = {
  youtube: {
    caption_type: 'SRT auto-generated with manual review',
    max_chars_per_line: 42,
    max_lines: 2,
    language: 'en-US',
    accessibility_standard: 'WCAG 2.1 AA',
    speaker_identification: false,
    sound_effects_notation: false,
    review_required: true
  },
  blog: {
    caption_type: 'Image alt text required for all images',
    max_chars_alt: 125,
    language: 'en-US',
    accessibility_standard: 'WCAG 2.1 AA',
    review_required: false
  },
  podcast: {
    caption_type: 'Full verbatim transcript',
    max_chars_per_line: 60,
    language: 'en-US',
    accessibility_standard: 'WCAG 2.1 AA',
    speaker_identification: true,
    timestamps: true,
    review_required: true
  },
  email: {
    caption_type: 'Image alt text for all images',
    max_chars_alt: 100,
    language: 'en-US',
    accessibility_standard: 'WCAG 2.1 AA',
    review_required: false
  }
};

const audioBriefs = {
  youtube: {
    target_lufs: -14,
    peak_ceiling_db: -1,
    noise_floor_db: -60,
    background_music: 'Optional, under -20dB relative to voice',
    voice_eq: 'High-pass at 80Hz, presence boost at 3-5kHz',
    format: 'AAC 320kbps in MP4 container'
  },
  blog: null,
  podcast: {
    target_lufs: -16,
    peak_ceiling_db: -1,
    noise_floor_db: -60,
    intro_music: 'Fade in 3s, maintain under voice level',
    outro_music: 'Fade out 5s',
    format: 'MP3 128kbps minimum, 320kbps preferred'
  },
  email: null
};

const captionBrief = captionBriefs[platform] || captionBriefs['youtube'];
const audioBrief = audioBriefs[platform] || null;

return [{
  json: {
    ...$json,
    caption_brief: captionBrief,
    audio_direction: audioBrief,
    caption_and_audio_brief_generated: true
  }
}];

const ppp = $json.platform_package_packet || {};
const pppPayload = ppp.payload || {};

const assetBriefPacket = {
  instance_id: 'ABP-' + Date.now(),
  artifact_family: 'asset_brief_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-330-Asset-Brief-Generator',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      source_platform: $json.target_platform,
      content_title: ($json.platform_metadata && ($json.platform_metadata.title || $json.platform_metadata.meta_title || $json.platform_metadata.episode_title || $json.platform_metadata.subject_line)) || 'Content Piece',
      asset_count: {
        thumbnail_briefs: 1,
        broll_cues: ($json.broll_cue_list || []).length,
        caption_briefs: 1,
        audio_direction_briefs: $json.audio_direction ? 1 : 0
      }
    },
    context: {
      sourced_from_packet_id: $json.source_platform_packet_id,
      target_platform: $json.target_platform,
      execution_requirements: pppPayload.context && pppPayload.context.execution_requirements
    },
    evidence: {
      lineage_references: [
        { type: 'platform_package_packet', id: $json.source_platform_packet_id },
        { type: 'execution_context_packet', id: $json.source_context_id },
        { type: 'dossier', id: $json.dossier_id }
      ],
      validation_checks: [
        { check: 'input_validation', result: $json.input_validation },
        { check: 'thumbnail_brief_generated', result: $json.thumbnail_brief_generated ? 'PASSED' : 'FAILED' },
        { check: 'broll_brief_generated', result: $json.broll_brief_generated ? 'PASSED' : 'FAILED' },
        { check: 'caption_audio_brief_generated', result: $json.caption_and_audio_brief_generated ? 'PASSED' : 'FAILED' }
      ]
    },
    quality: {
      asset_brief_completeness: 0.95,
      gate_checks: {
        thumbnail_brief_complete: !!$json.thumbnail_brief,
        broll_brief_complete: !!$json.broll_cue_list && $json.broll_cue_list.length > 0,
        caption_brief_complete: !!$json.caption_brief,
        audio_brief_addressed: true
      },
      asset_brief_ready_for_wf400: true
    },
    status: {
      decision_path: 'PROCEED_TO_CWF-340',
      next_workflow: 'CWF-340',
      escalation_needed: false
    },
    assets: {
      thumbnail_brief: $json.thumbnail_brief || {},
      broll_cue_list: $json.broll_cue_list || [],
      caption_brief: $json.caption_brief || {},
      audio_direction: $json.audio_direction || null
    }
  }
};

return [{ json: assetBriefPacket }];

const pkt = $json;
const payload = pkt.payload || {};

return [{
  json: {
    workflow_id: 'CWF-330',
    execution_status: 'SUCCESS',
    asset_brief_packet: pkt,
    next_workflow: 'CWF-340',
    dossier_delta: {
      namespace: 'context',
      mutation_type: 'append_to_array',
      target: 'dossier.context.asset_brief_packets',
      value: {
        instance_id: pkt.instance_id,
        artifact_family: 'asset_brief_packet',
        target_platform: payload.context && payload.context.target_platform,
        asset_count: payload.narrative && payload.narrative.asset_count,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-330',
        operation: 'CREATE_ASSET_BRIEF_PACKET',
        sourced_from: pkt.dossier_ref
      }
    },
    decision: 'PROCEED_TO_CWF-340'
  }
}];
